#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct Node {
    int val;
    struct Node* left;
    struct Node* right;
} Node;

Node* getNode(Node** map, int* used, int key) {
    if (!used[key]) {
        map[key] = (Node*)malloc(sizeof(Node));
        map[key]->val = key;
        map[key]->left = map[key]->right = NULL;
        used[key] = 1;
    }
    return map[key];
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        // value range up to 1e6, allocate map accordingly
        static Node* nodeMap[1000001];
        static char used[1000001];
        memset(nodeMap, 0, sizeof(nodeMap));
        memset(used, 0, sizeof(used));
        int childSeen[1000001] = {0};
        Node* root = NULL;
        for (int i = 0; i < N-1; ++i) {
            int p, c; char pos;
            scanf("%d %d %c", &p, &c, &pos);
            Node* parent = getNode(nodeMap, used, p);
            Node* child  = getNode(nodeMap, used, c);
            if (pos == 'L') parent->left = child; else parent->right = child;
            childSeen[c] = 1;
        }
        // find root (node that never appeared as child)
        for (int i = 0; i <= 1000000; ++i) {
            if (used[i] && !childSeen[i]) { root = nodeMap[i]; break; }
        }
        // BFS zigzag
        Node** q = (Node**)malloc(sizeof(Node*) * N);
        int front = 0, rear = 0;
        q[rear++] = root;
        int leftToRight = 1;
        while (front < rear) {
            int sz = rear - front;
            int* level = (int*)malloc(sizeof(int) * sz);
            for (int i = 0; i < sz; ++i) {
                Node* cur = q[front++];
                int idx = leftToRight ? i : sz-1-i;
                level[idx] = cur->val;
                if (cur->left) q[rear++] = cur->left;
                if (cur->right) q[rear++] = cur->right;
            }
            for (int i = 0; i < sz; ++i) {
                if (i) printf(" ");
                printf("%d", level[i]);
            }
            printf("\n");
            free(level);
            leftToRight = !leftToRight;
        }
        free(q);
        // free nodes
        for (int i = 0; i <= 1000000; ++i) if (used[i]) free(nodeMap[i]);
    }
    return 0;
}

