struct Node {
    int val;
    Node* left;
    Node* right;
    Node(int v): val(v), left(nullptr), right(nullptr) {}
};

int main(){
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        unordered_map<int, Node*> mp;
        vector<int> childFlag(N*2+5,0); // enough size, will use map for existence
        Node* root = nullptr;
        for(int i=0;i<N-1;++i){
            int p,c; char pos; cin>>p>>c>>pos;
            if(mp.find(p)==mp.end()) mp[p]=new Node(p);
            if(mp.find(c)==mp.end()) mp[c]=new Node(c);
            if(pos=='L') mp[p]->left = mp[c]; else mp[p]->right = mp[c];
            childFlag[c]=1;
        }
        for(auto &kv: mp){
            if(!childFlag[kv.first]){ root = kv.second; break; }
        }
        queue<Node*> q; q.push(root);
        bool leftToRight = true;
        while(!q.empty()){
            int sz = q.size();
            vector<int> level(sz);
            for(int i=0;i<sz;++i){
                Node* cur = q.front(); q.pop();
                int idx = leftToRight? i : sz-1-i;
                level[idx]=cur->val;
                if(cur->left) q.push(cur->left);
                if(cur->right) q.push(cur->right);
            }
            for(int i=0;i<sz;++i){
                if(i) cout<<' ';
                cout<<level[i];
            }
            cout<<'\n';
            leftToRight=!leftToRight;
        }
        for(auto &kv: mp) delete kv.second;
    }
    return 0;
}

