import java.io.*;
import java.util.*;

public class Main {
    static class Node {
        int val;
        Node left, right;
        Node(int v){ val=v; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Map<Integer, Node> map = new HashMap<>();
            Set<Integer> childSet = new HashSet<>();
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int p = Integer.parseInt(st.nextToken());
                int c = Integer.parseInt(st.nextToken());
                char pos = st.nextToken().charAt(0);
                Node parent = map.computeIfAbsent(p, k -> new Node(k));
                Node child = map.computeIfAbsent(c, k -> new Node(k));
                if (pos == 'L') parent.left = child; else parent.right = child;
                childSet.add(c);
            }
            Node root = null;
            for (int key : map.keySet()) {
                if (!childSet.contains(key)) { root = map.get(key); break; }
            }
            Deque<Node> q = new ArrayDeque<>();
            q.add(root);
            boolean leftToRight = true;
            while (!q.isEmpty()) {
                int sz = q.size();
                int[] level = new int[sz];
                for (int i = 0; i < sz; i++) {
                    Node cur = q.pollFirst();
                    int idx = leftToRight ? i : sz - 1 - i;
                    level[idx] = cur.val;
                    if (cur.left != null) q.addLast(cur.left);
                    if (cur.right != null) q.addLast(cur.right);
                }
                for (int i = 0; i < sz; i++) {
                    if (i > 0) out.append(' ');
                    out.append(level[i]);
                }
                out.append('\n');
                leftToRight = !leftToRight;
            }
        }
        System.out.print(out.toString());
    }
}

