import sys
from collections import deque

def solve():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nodes = {}
        child = set()
        for _ in range(N-1):
            p, c, pos = next(it).split()
            p = int(p); c = int(c)
            if p not in nodes:
                nodes[p] = [None, None]  # left, right
            if c not in nodes:
                nodes[c] = [None, None]
            if pos == 'L':
                nodes[p][0] = c
            else:
                nodes[p][1] = c
            child.add(c)
        # find root
        root = None
        for v in nodes:
            if v not in child:
                root = v
                break
        q = deque([root])
        left_to_right = True
        while q:
            sz = len(q)
            level = [0]*sz
            for i in range(sz):
                cur = q.popleft()
                idx = i if left_to_right else sz-1-i
                level[idx] = cur
                left, right = nodes[cur]
                if left is not None:
                    q.append(left)
                if right is not None:
                    q.append(right)
            out_lines.append(' '.join(map(str, level)))
            left_to_right = not left_to_right
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

