const lines = require('fs').readFileSync(0,'utf-8').trim().split('\n');
let idx = 0;
const T = parseInt(lines[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = parseInt(lines[idx++]);
  const nodes = new Map(); // value -> {left:null,right:null}
  const childSet = new Set();
  for (let i = 0; i < N - 1; i++) {
    const [pStr, cStr, pos] = lines[idx++].trim().split(/\s+/);
    const p = parseInt(pStr), c = parseInt(cStr);
    if (!nodes.has(p)) nodes.set(p, {left: null, right: null});
    if (!nodes.has(c)) nodes.set(c, {left: null, right: null});
    const parent = nodes.get(p);
    if (pos === 'L') parent.left = c; else parent.right = c;
    childSet.add(c);
  }
  let root = null;
  for (let key of nodes.keys()) {
    if (!childSet.has(key)) { root = key; break; }
  }
  let queue = [root];
  let leftToRight = true;
  while (queue.length) {
    const sz = queue.length;
    const level = new Array(sz);
    for (let i = 0; i < sz; i++) {
      const cur = queue.shift();
      const idxPos = leftToRight ? i : sz - 1 - i;
      level[idxPos] = cur;
      const node = nodes.get(cur);
      if (node.left !== null) queue.push(node.left);
      if (node.right !== null) queue.push(node.right);
    }
    output.push(level.join(' '));
    leftToRight = !leftToRight;
  }
}
